/**
 * @name Path traversal in Camel ResourceEndpoint - getResource with user input
 * @description User-controlled HTTP path info flows to resource loading operations without path validation
 * @kind path-problem
 * @problem.severity error
 * @id java/camel-resource-endpoint-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ResourcePathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // HTTP request URI/path parameters
    exists(MethodCall mc |
      (mc.getMethod().hasName("getPathInfo") or
       mc.getMethod().hasName("getRequestURI") or
       mc.getMethod().hasName("getServletPath") or
       mc.getMethod().hasName("getParameter") or
       mc.getMethod().hasName("getHeader")) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassLoader.getResource or getResourceAsStream
    exists(MethodCall mc |
      (mc.getMethod().hasName("getResource") or
       mc.getMethod().hasName("getResourceAsStream")) and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Spring ClassPathResource / FileSystemResource constructor
    exists(ClassInstanceExpr ce |
      (ce.getConstructor().getDeclaringType().hasName("ClassPathResource") or
       ce.getConstructor().getDeclaringType().hasName("FileSystemResource")) and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    // ResourceHelper.resolveMandatoryResourceAsUrl
    exists(MethodCall mc |
      (mc.getMethod().hasName("resolveMandatoryResourceAsUrl") or
       mc.getMethod().hasName("resolveResourceAsUrl") or
       mc.getMethod().hasName("loadResourceAsStream")) and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module ResourcePathTraversalFlow = TaintTracking::Global<ResourcePathTraversalConfig>;
import ResourcePathTraversalFlow::PathGraph

from ResourcePathTraversalFlow::PathNode source, ResourcePathTraversalFlow::PathNode sink
where ResourcePathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: HTTP path flows to resource loading from $@.", source.getNode(), "user-controlled HTTP input"

/**
 * @name Camel REST catalog servlet - user input to ClassLoader.getResourceAsStream
 * @description HTTP request path parameters flow to ClassLoader.getResourceAsStream in CamelCatalogRest
 * @kind path-problem
 * @problem.severity error
 * @id java/camel-catalog-rest-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module CatalogRestConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
    or
    // getPathInfo, getRequestURI, etc.
    exists(MethodCall mc |
      (mc.getMethod().hasName("getPathInfo") or
       mc.getMethod().hasName("getRequestURI") or
       mc.getMethod().hasName("getQueryString") or
       mc.getMethod().hasName("getParameter")) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassLoader.getResourceAsStream or getResource
    exists(MethodCall mc |
      (mc.getMethod().hasName("getResourceAsStream") or
       mc.getMethod().hasName("getResource")) and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Class.getResourceAsStream
    exists(MethodCall mc |
      mc.getMethod().hasName("getResourceAsStream") and
      mc.getQualifier().getType() instanceof TypeClass and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module CatalogRestFlow = TaintTracking::Global<CatalogRestConfig>;
import CatalogRestFlow::PathGraph

from CatalogRestFlow::PathNode source, CatalogRestFlow::PathNode sink
where CatalogRestFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "HTTP input flows to ClassLoader.getResourceAsStream from $@.", source.getNode(), "user-controlled source"
